// Mimics the OpenMP structure: chunks of 4096, f = data[chunk_start]
template <typename Element, size_t compute_iterations>
__global__ void bench_element_kernel(Element* data, size_t total_len) {
  constexpr size_t static_chunk_size = 4096;
  size_t chunk_start = blockIdx.x * static_chunk_size;
  size_t idx = chunk_start + threadIdx.x;

  if (idx >= total_len) return;

  Element f = data[chunk_start];
  Element t = data[idx];

  for (size_t j = 0; j < compute_iterations; j++) {
    t = t * t + f;
  }

  data[idx] = t;
}

