// CUDA Kernel for bench_block logic (8-wide version)
template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__global__ void bench_block_kernel_8(Element* data, Element* sum_ptr, size_t total_len) {
  size_t base_idx = blockIdx.x * static_chunk_size + threadIdx.x * 8;
  if (base_idx >= total_len) return;

  Element f[8];
  for(int k=0; k<8; ++k) {
      if (base_idx + k < total_len) f[k] = data[base_idx + k];
      else f[k] = 0;
  }

  Element t[8];
  for(int k=0; k<8; ++k) t[k] = f[k];

  size_t full_iters = compute_iterations / 8;
  for (size_t j = 0; j < full_iters; j++) {
    t[0] = t[0] * t[0] + f[0];
    t[1] = t[1] * t[1] + f[1];
    t[2] = t[2] * t[2] + f[2];
    t[3] = t[3] * t[3] + f[3];
    t[4] = t[4] * t[4] + f[4];
    t[5] = t[5] * t[5] + f[5];
    t[6] = t[6] * t[6] + f[6];
    t[7] = t[7] * t[7] + f[7];
  }

  size_t rem = compute_iterations % 8;
  if (rem > 0) t[0] = t[0] * t[0] + f[0];
  if (rem > 1) t[1] = t[1] * t[1] + f[1];
  if (rem > 2) t[2] = t[2] * t[2] + f[2];
  if (rem > 3) t[3] = t[3] * t[3] + f[3];
  if (rem > 4) t[4] = t[4] * t[4] + f[4];
  if (rem > 5) t[5] = t[5] * t[5] + f[5];
  if (rem > 6) t[6] = t[6] * t[6] + f[6];

  Element block_sum = t[0] + t[1] + t[2] + t[3] + t[4] + t[5] + t[6] + t[7];

  __shared__ Element shared_data[static_chunk_size];
  shared_data[threadIdx.x] = block_sum;
  __syncthreads();

  if (static_chunk_size >= 1024) { if (threadIdx.x < 512) shared_data[threadIdx.x] += shared_data[threadIdx.x + 512]; __syncthreads(); }
  if (static_chunk_size >= 512) { if (threadIdx.x < 256) shared_data[threadIdx.x] += shared_data[threadIdx.x + 256]; __syncthreads(); }
  if (static_chunk_size >= 256) { if (threadIdx.x < 128) shared_data[threadIdx.x] += shared_data[threadIdx.x + 128]; __syncthreads(); }
  if (static_chunk_size >= 128) { if (threadIdx.x < 64) shared_data[threadIdx.x] += shared_data[threadIdx.x + 64]; __syncthreads(); }
  if (threadIdx.x < 32) {
    volatile Element* vsm = shared_data;
    vsm[threadIdx.x] += vsm[threadIdx.x + 32];
    vsm[threadIdx.x] += vsm[threadIdx.x + 16];
    vsm[threadIdx.x] += vsm[threadIdx.x + 8];
    vsm[threadIdx.x] += vsm[threadIdx.x + 4];
    vsm[threadIdx.x] += vsm[threadIdx.x + 2];
    vsm[threadIdx.x] += vsm[threadIdx.x + 1];
  }

  if (threadIdx.x == 0) {
    atomicAdd(sum_ptr, shared_data[0]);
  }
}

template <typename Element, size_t compute_iterations>
size_t bench_cuda(size_t len, const Element seed1, const Element seed2, Element* src_dev, Element* sum_dev) {
  constexpr size_t static_chunk_size = 4096;
  // Reset sum
  Element zero = 0;
  cudaMemcpy(sum_dev, &zero, sizeof(Element), cudaMemcpyHostToDevice);

  int threads_per_block = static_chunk_size;
  int blocks = (len + static_chunk_size - 1) / static_chunk_size;

  // Launch kernel
  bench_block_kernel_8<Element, compute_iterations, static_chunk_size>(blocks, threads_per_block, src_dev, sum_dev, len);

  cudaDeviceSynchronize();

  Element result;
  cudaMemcpy(&result, sum_dev, sizeof(Element), cudaMemcpyDeviceToHost);

  *src_dev = result; // Mimic *src = sum
  return len;
}

